import{_ as a,a as t,b as i,c as s,d as o,e as r}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as n,o as l,c as d,a2 as p}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"Géolocalisation IP et gestion des utilisateurs","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Other/ip-geolocation-and-user-management.md","filePath":"fr-FR/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),u={name:"fr-FR/Other/ip-geolocation-and-user-management.md"};function c(m,e,h,g,f,b){return l(),d("div",null,[...e[0]||(e[0]=[p('<h1 id="geolocalisation-ip-et-gestion-des-utilisateurs" tabindex="-1">Géolocalisation IP et gestion des utilisateurs <a class="header-anchor" href="#geolocalisation-ip-et-gestion-des-utilisateurs" aria-label="Permalink to &quot;Géolocalisation IP et gestion des utilisateurs&quot;">​</a></h1><p>La géolocalisation IP transforme les adresses IP issues des uploads, connexions et journaux en localisations approximatives.</p><p>Une fois configurée, elle rend l’origine des uploads et accès plus lisible dans le panneau. La gestion des utilisateurs permet aussi de bloquer ou réautoriser l’upload pour des IP suspectes.</p><h2 id="ou-configurer" tabindex="-1">Où configurer <a class="header-anchor" href="#ou-configurer" aria-label="Permalink to &quot;Où configurer&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Autres paramètres -&gt; Géolocalisation IP</span></span></code></pre></div><p><img src="'+a+`" alt="Géolocalisation IP" loading="lazy"></p><h2 id="parametres-disponibles" tabindex="-1">Paramètres disponibles <a class="header-anchor" href="#parametres-disponibles" aria-label="Permalink to &quot;Paramètres disponibles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paramètre</th><th>Description</th></tr></thead><tbody><tr><td>Langue de géolocalisation</td><td>Définit la langue des localisations affichées</td></tr><tr><td>MaxMind Account ID</td><td>ID de compte pour MaxMind GeoLite Web Service</td></tr><tr><td>MaxMind License Key</td><td>Clé de licence MaxMind</td></tr><tr><td>Tencent Map Key</td><td>Utile pour les adresses en Chine continentale</td></tr><tr><td>ipapi Key</td><td>Clé APILayer ipapi avec prise en charge multilingue</td></tr></tbody></table><p>Ne renseignez que les services nécessaires. Sans clé, ImgBed essaie des sources gratuites intégrées, mais elles peuvent être moins stables ou moins précises.</p><h2 id="recommandation-pour-le-francais" tabindex="-1">Recommandation pour le français <a class="header-anchor" href="#recommandation-pour-le-francais" aria-label="Permalink to &quot;Recommandation pour le français&quot;">​</a></h2><p>Pour afficher les localisations en français ou en plusieurs langues, configurez MaxMind et ajoutez ipapi si vous voulez de meilleurs résultats multilingues.</p><h2 id="configurer-maxmind" tabindex="-1">Configurer MaxMind <a class="header-anchor" href="#configurer-maxmind" aria-label="Permalink to &quot;Configurer MaxMind&quot;">​</a></h2><p>MaxMind nécessite :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Récupérez l’Account ID dans le tableau de bord MaxMind, créez une License Key, puis collez les deux valeurs dans ImgBed.</p><p><img src="`+t+'" alt="Configuration MaxMind" loading="lazy"></p><h2 id="configurer-ipapi" tabindex="-1">Configurer ipapi <a class="header-anchor" href="#configurer-ipapi" aria-label="Permalink to &quot;Configurer ipapi&quot;">​</a></h2><p>Copiez l’API Key depuis la console ipapi.</p><p><img src="'+i+'" alt="Configuration ipapi" loading="lazy"></p><p>Collez-la dans <code>ipapi Key</code> dans ImgBed, puis enregistrez.</p><h2 id="gestion-des-utilisateurs" tabindex="-1">Gestion des utilisateurs <a class="header-anchor" href="#gestion-des-utilisateurs" aria-label="Permalink to &quot;Gestion des utilisateurs&quot;">​</a></h2><p>La gestion des utilisateurs s’ouvre depuis le haut du panneau d’administration.</p><p><img src="'+s+'" alt="Gestion des utilisateurs" loading="lazy"></p><p>Elle regroupe l’activité par IP.</p><table tabindex="0"><thead><tr><th>Champ</th><th>Description</th></tr></thead><tbody><tr><td>IP</td><td>IP d’origine</td></tr><tr><td>Localisation</td><td>Localisation approximative résolue depuis l’IP</td></tr><tr><td>Taille totale envoyée</td><td>Somme des fichiers envoyés par cette IP</td></tr><tr><td>Nombre d’uploads</td><td>Nombre d’envois</td></tr><tr><td>Upload autorisé</td><td>Désactivez pour bloquer les nouveaux uploads depuis cette IP</td></tr></tbody></table><p>Ouvrez la flèche à gauche pour voir les fichiers envoyés par cette IP : nom, prévisualisation, taille, résultat de modération, état et heure d’envoi.</p><p><img src="'+o+'" alt="Filtres avancés" loading="lazy"></p><h2 id="conseils-d-exploitation" tabindex="-1">Conseils d’exploitation <a class="header-anchor" href="#conseils-d-exploitation" aria-label="Permalink to &quot;Conseils d’exploitation&quot;">​</a></h2><ul><li>Avant de bloquer une IP, vérifiez les fichiers envoyés.</li><li>Utilisez recherche et tri pour repérer les IP récentes, très actives ou consommatrices.</li><li>La localisation IP reste une estimation. Utilisez-la comme signal d’aide, pas comme preuve absolue.</li></ul><p><img src="'+r+'" alt="Affichage mobile" loading="lazy"></p>',30)])])}const _=n(u,[["render",c]]);export{P as __pageData,_ as default};
